33	struct InferredMemoryDetector : public TimingPatternInterpretor,
34									public ast::ASTVisitor<InferredMemoryDetector,
35											ast::VisitFlags::Statements | ast::VisitFlags::Expressions>,
36									public DiagnosticIssuer
37	{
38		Yosys::pool<const ast::Symbol *> memory_candidates;
39		std::function<bool(const ast::InstanceSymbol &sym)> should_dissolve;
40		bool disallow_implicit = false;
41	
42		InferredMemoryDetector(SynthesisSettings &settings,
43				std::function<bool(const ast::InstanceSymbol &sym)> should_dissolve,
44				EvalContext &evalCtx)
45			: TimingPatternInterpretor(settings, (DiagnosticIssuer &)*this, evalCtx),
46			  should_dissolve(should_dissolve),
47			  disallow_implicit(settings.no_implicit_memories.value_or(false))
48		{}
