50		void process(const ast::Symbol &root)
51		{
52			auto first_pass = ast::makeVisitor(
53					[&](auto &, const ast::VariableSymbol &symbol) {
54						if (symbol.lifetime == ast::VariableLifetime::Static &&
55								symbol.getType().isUnpackedArray() &&
56								symbol.getType().hasFixedRange() &&
57								(!disallow_implicit || find_user_hint(symbol)) &&
58								symbol.getParentScope()->getContainingInstance() &&
59								symbol.getParentScope()
60										->getContainingInstance()
61										->parentInstance->isModule() &&
62								symbol.kind != ast::SymbolKind::FormalArgument)
63							memory_candidates.insert(&symbol);
64					},
65					[&](auto &visitor, const ast::GenerateBlockSymbol &symbol) {
66						if (symbol.isUninstantiated)
67							return;
68						visitor.visitDefault(symbol);
69					},
70					[&](auto &visitor, const ast::InstanceSymbol &symbol) {
71						if (should_dissolve(symbol))
72							visitor.visitDefault(symbol);
73					});
74			root.visit(first_pass);
75			root.visit(*this);
76		}
