79									ast::VisitFlags::Statements | ast::VisitFlags::Expressions>
80		{
81			InferredMemoryDetector &rhs;
82			LHSVisitor(InferredMemoryDetector &rhs) : rhs(rhs) {}
83	
84			void handle(const ast::ElementSelectExpression &expr)
85			{
