98			{
99				rhs.disqualify(expr.symbol, expr.sourceRange.start());
100			}
101		};
102	
103		std::optional<std::string_view> find_user_hint(const ast::Symbol &symbol)
104		{
105			const static std::set<std::string> recognized = {"ram_block", "rom_block", "ram_style",
106					"rom_style", "ramstyle", "romstyle", "syn_ramstyle", "syn_romstyle"};
107	
108			for (auto attr : global_compilation->getAttributes(symbol)) {
109				if (recognized.count(std::string{attr->name}) && !attr->getValue().isFalse())
110					return attr->name;
111			}
112			return {};
113		}
114	
115		void disqualify(const ast::Symbol &symbol, slang::SourceLocation loc)
116		{
117			std::optional<std::string_view> found_attr;
118			if (memory_candidates.count(&symbol) && (found_attr = find_user_hint(symbol))) {
119				auto &diag = add_diag(diag::MemoryNotInferred, symbol.location);
120				diag << found_attr.value();
121				diag.addNote(diag::NoteUsageBlame, loc);
122			}
123	
124			memory_candidates.erase(&symbol);
125		}
126	
127		void handle(const ast::ValueExpressionBase &expr)
128		{
129			disqualify(expr.symbol, expr.sourceRange.start());
130		}
131	
132		void handle(const ast::PortSymbol &symbol)
133		{
134			if (symbol.internalSymbol)
135				disqualify(*symbol.internalSymbol, symbol.location);
136			visitDefault(symbol);
137		}
138	
139		void handle(const ast::AssignmentExpression &assign)
140		{
141			LHSVisitor lhs(*this);
142			assign.left().visit(lhs);
143			assign.right().visit(*this);
144		}
145	
146		void handle(const ast::ElementSelectExpression &expr)
147		{
148			if (ast::ValueExpressionBase::isKind(expr.value().kind)) {
149				// do nothing
150			} else {
151				expr.value().visit(*this);
152			}
153	
154			expr.selector().visit(*this);
155		}
156	
157		bool wr_allowed = false;
158	
159		void handle(const ast::ExpressionStatement &stmt)
160		{
161			if (stmt.expr.kind == ast::ExpressionKind::Assignment &&
162					stmt.expr.as<ast::AssignmentExpression>().isNonBlocking() && wr_allowed) {
163				auto &assign = stmt.expr.as<ast::AssignmentExpression>();
164				assign.right().visit(*this);
165	
166				const ast::Expression *raw_lexpr = &assign.left();
167				LHSVisitor fallback(*this);
168				while (true) {
169					switch (raw_lexpr->kind) {
170					case ast::ExpressionKind::RangeSelect: {
171						auto &sel = raw_lexpr->as<ast::RangeSelectExpression>();
172						sel.left().visit(*this);
173						sel.right().visit(*this);
174						raw_lexpr = &sel.value();
175					} break;
176					case ast::ExpressionKind::ElementSelect: {
177						auto &sel = raw_lexpr->as<ast::ElementSelectExpression>();
178						sel.selector().visit(*this);
179						raw_lexpr = &sel.value();
180						if (ast::ValueExpressionBase::isKind(sel.value().kind)) {
181							// a potential memory candidate
182							return;
183						}
184					} break;
185					case ast::ExpressionKind::MemberAccess: {
186						const auto &acc = raw_lexpr->as<ast::MemberAccessExpression>();
187						raw_lexpr = &acc.value();
188					} break;
189					default: raw_lexpr->visit(fallback); return;
190					}
191				}
192	
193				log_abort(); // unreachable
194			}
195	
196			stmt.expr.visit(*this);
197		}
198	
199		void handle(const ast::GenerateBlockSymbol &sym)
200		{
201			if (sym.isUninstantiated)
202				return;
203			visitDefault(sym);
204		}
205	
206		void handle(const ast::ProceduralBlockSymbol &symbol) { interpret(symbol); }
207	
208		virtual void handle_comb_like_process(
209				const ast::ProceduralBlockSymbol &, const ast::Statement &body)
210		{
211			body.visit(*this);
212		}
213	
214		virtual void handle_ff_process(const ast::ProceduralBlockSymbol &,
215				const ast::SignalEventControl &, const ast::StatementBlockSymbol *,
216				std::vector<const ast::Statement *> prologue, const ast::Statement &sync_body,
217				std::span<AsyncBranch> async)
218		{
219			for (auto stmt : prologue)
220				stmt->visit(*this);
221			for (auto &branch : async)
222				branch.body.visit(*this);
223			wr_allowed = true;
224			sync_body.visit(*this);
225			wr_allowed = false;
226		}
227	
228		virtual void handle_initial_process(const ast::ProceduralBlockSymbol &, const ast::Statement &)
229		{
230			// Initial processes have no influence over memory inference
231		}
232	
233		void handle(const ast::InstanceSymbol &sym)
234		{
235			if (should_dissolve(sym)) {
236				visitDefault(sym);
237			} else {
238				for (auto *conn : sym.getPortConnections()) {
239					if (auto expr = conn->getExpression())
240						expr->visit(*this);
241				}
242			}
243		}
244	};
